import{_ as i,o as a,c as o,ag as s}from"./chunks/framework.CTpQozEL.js";const h=JSON.parse('{"title":"Memory 개요","description":"OpenClaw가 세션 간에 정보를 기억하는 방식","frontmatter":{"title":"Memory 개요","description":"OpenClaw가 세션 간에 정보를 기억하는 방식"},"headers":[],"relativePath":"concepts/memory.md","filePath":"concepts/memory.md","lastUpdated":null}'),l={name:"concepts/memory.md"};function r(n,e,t,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<p>OpenClaw는 에이전트의 워크스페이스에 <strong>평범한 Markdown 파일</strong>을 기록하는 방식으로 정보를 기억합니다. 모델은 디스크에 저장된 내용만 &quot;기억&quot;하며, 숨겨진 상태는 없습니다.</p><h2 id="동작-방식" tabindex="-1">동작 방식 <a class="header-anchor" href="#동작-방식" aria-label="Permalink to &quot;동작 방식&quot;">​</a></h2><p>에이전트에는 memory 관련 세 가지 파일이 있습니다.</p><ul><li><strong><code>MEMORY.md</code></strong> -- 장기 memory. 지속적인 사실, 선호, 결정 사항을 담습니다. 모든 DM 세션 시작 시 자동으로 로드됩니다.</li><li><strong><code>memory/YYYY-MM-DD.md</code></strong> -- 일일 노트. 진행 중인 맥락과 관찰 내용을 기록합니다. 오늘과 어제의 노트가 자동으로 로드됩니다.</li><li><strong><code>DREAMS.md</code></strong> (선택 사항) -- 사람이 검토할 수 있는 Dream Diary와 dreaming sweep 요약이 담깁니다. grounded historical backfill 항목도 포함됩니다.</li></ul><p>이 파일들은 에이전트 워크스페이스(기본값: <code>~/.openclaw/workspace</code>)에 있습니다.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>에이전트가 어떤 내용을 기억했으면 한다면, 그냥 &quot;내가 TypeScript를 선호한다는 걸 기억해줘&quot;라고 말씀하시면 됩니다. 적절한 파일에 알아서 기록해줍니다.</p></div><h2 id="memory-도구" tabindex="-1">Memory 도구 <a class="header-anchor" href="#memory-도구" aria-label="Permalink to &quot;Memory 도구&quot;">​</a></h2><p>에이전트는 memory를 다루기 위한 두 가지 도구를 가지고 있습니다.</p><ul><li><strong><code>memory_search</code></strong> -- 원래 문구와 표현이 달라도 의미 기반 검색으로 관련 노트를 찾아냅니다.</li><li><strong><code>memory_get</code></strong> -- 특정 memory 파일이나 라인 범위를 읽습니다.</li></ul><p>두 도구 모두 활성화된 memory 플러그인(기본값: <code>memory-core</code>)이 제공합니다.</p><h2 id="memory-wiki-동반-플러그인" tabindex="-1">Memory Wiki 동반 플러그인 <a class="header-anchor" href="#memory-wiki-동반-플러그인" aria-label="Permalink to &quot;Memory Wiki 동반 플러그인&quot;">​</a></h2><p>지속 memory가 원시 노트 수준을 넘어 관리되는 지식 베이스처럼 동작하길 원한다면, 번들로 제공되는 <code>memory-wiki</code> 플러그인을 사용하세요.</p><p><code>memory-wiki</code>는 지속 지식을 wiki 저장소로 컴파일하며, 다음 기능을 제공합니다.</p><ul><li>결정적(deterministic) 페이지 구조</li><li>구조화된 주장(claim)과 근거(evidence)</li><li>모순(contradiction)과 최신성(freshness) 추적</li><li>생성된 대시보드</li><li>에이전트/런타임 소비자를 위한 컴파일된 digest</li><li><code>wiki_search</code>, <code>wiki_get</code>, <code>wiki_apply</code>, <code>wiki_lint</code> 같은 wiki 전용 도구</li></ul><p>이것은 활성 memory 플러그인을 대체하지 않습니다. 활성 memory 플러그인이 여전히 recall, promotion, dreaming을 담당하며, <code>memory-wiki</code>는 그 옆에 provenance가 풍부한 지식 계층을 추가합니다.</p><p><a href="/openclaw-docs-ko/plugins/memory-wiki">Memory Wiki</a>를 참고하세요.</p><h2 id="memory-검색" tabindex="-1">Memory 검색 <a class="header-anchor" href="#memory-검색" aria-label="Permalink to &quot;Memory 검색&quot;">​</a></h2><p>embedding 제공자가 설정되어 있으면, <code>memory_search</code>는 <strong>hybrid search</strong>를 사용합니다. 벡터 유사도(의미)와 키워드 매칭(ID나 코드 기호 같은 정확한 용어)을 결합한 방식입니다. 지원되는 제공자의 API 키가 있다면 추가 설정 없이도 바로 동작합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>OpenClaw는 사용 가능한 API 키를 기반으로 embedding 제공자를 자동 감지합니다. OpenAI, Gemini, Voyage, Mistral 키 중 하나가 설정되어 있다면 memory 검색이 자동으로 활성화됩니다.</p></div><p>검색 동작 방식, 튜닝 옵션, 제공자 설정에 대한 자세한 내용은 <a href="/openclaw-docs-ko/concepts/memory-search">Memory Search</a>를 참고하세요.</p><h2 id="memory-백엔드" tabindex="-1">Memory 백엔드 <a class="header-anchor" href="#memory-백엔드" aria-label="Permalink to &quot;Memory 백엔드&quot;">​</a></h2><blockquote><p><strong>Builtin (기본값)</strong> SQLite 기반. 키워드 검색, 벡터 유사도, hybrid search가 바로 동작합니다. 추가 의존성이 없습니다.</p></blockquote><blockquote><p><strong>QMD</strong> reranking, query expansion, 워크스페이스 바깥 디렉토리 인덱싱 기능을 갖춘 local-first 사이드카입니다.</p></blockquote><blockquote><p><strong>Honcho</strong> 사용자 모델링, 의미 검색, 멀티 에이전트 인지 기능을 갖춘 AI 네이티브 크로스 세션 memory입니다. 플러그인 방식으로 설치합니다.</p></blockquote><h2 id="knowledge-wiki-계층" tabindex="-1">Knowledge wiki 계층 <a class="header-anchor" href="#knowledge-wiki-계층" aria-label="Permalink to &quot;Knowledge wiki 계층&quot;">​</a></h2><blockquote><p><strong>Memory Wiki</strong> 지속 memory를 provenance가 풍부한 wiki 저장소로 컴파일합니다. claim, 대시보드, bridge mode, Obsidian 친화 워크플로우를 제공합니다.</p></blockquote><h2 id="자동-memory-flush" tabindex="-1">자동 memory flush <a class="header-anchor" href="#자동-memory-flush" aria-label="Permalink to &quot;자동 memory flush&quot;">​</a></h2><p><a href="/openclaw-docs-ko/concepts/compaction">compaction</a>이 대화를 요약하기 전에, OpenClaw는 에이전트에게 중요한 맥락을 memory 파일에 저장하라고 상기시키는 조용한 턴(silent turn)을 실행합니다. 이 기능은 기본 활성화되어 있으며 별도 설정이 필요 없습니다.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>memory flush는 compaction 과정에서 맥락이 손실되는 것을 방지합니다. 대화 중에 아직 파일로 저장되지 않은 중요한 사실이 있다면, 요약이 일어나기 전에 자동으로 저장됩니다.</p></div><h2 id="dreaming" tabindex="-1">Dreaming <a class="header-anchor" href="#dreaming" aria-label="Permalink to &quot;Dreaming&quot;">​</a></h2><p>Dreaming은 memory의 선택적 백그라운드 통합 과정입니다. 단기 신호를 수집하고, 후보를 점수화한 뒤, 기준을 통과한 항목만 장기 memory(<code>MEMORY.md</code>)로 승격합니다.</p><p>장기 memory의 신호 밀도를 높게 유지하도록 설계되어 있습니다.</p><ul><li><strong>Opt-in</strong>: 기본 비활성화.</li><li><strong>Scheduled</strong>: 활성화되면 <code>memory-core</code>가 전체 dreaming sweep을 위한 반복 cron 작업 하나를 자동 관리합니다.</li><li><strong>Thresholded</strong>: 승격은 score, recall 빈도, 쿼리 다양성 게이트를 통과해야 합니다.</li><li><strong>Reviewable</strong>: phase 요약과 diary 항목이 사람이 검토할 수 있도록 <code>DREAMS.md</code>에 기록됩니다.</li></ul><p>phase 동작, 점수화 신호, Dream Diary 세부 사항은 <a href="/openclaw-docs-ko/concepts/dreaming">Dreaming</a>을 참고하세요.</p><h2 id="grounded-backfill과-live-promotion" tabindex="-1">Grounded backfill과 live promotion <a class="header-anchor" href="#grounded-backfill과-live-promotion" aria-label="Permalink to &quot;Grounded backfill과 live promotion&quot;">​</a></h2><p>dreaming 시스템에는 이제 긴밀하게 연관된 두 가지 리뷰 레인이 있습니다.</p><ul><li><strong>Live dreaming</strong>은 <code>memory/.dreams/</code> 아래의 단기 dreaming 저장소에서 동작하며, 일반 deep phase가 <code>MEMORY.md</code>로 graduate할 대상을 결정할 때 사용하는 방식입니다.</li><li><strong>Grounded backfill</strong>은 과거 <code>memory/YYYY-MM-DD.md</code> 노트를 독립 day 파일로 읽고, 구조화된 리뷰 출력을 <code>DREAMS.md</code>에 기록합니다.</li></ul><p>Grounded backfill은 <code>MEMORY.md</code>를 수동으로 편집하지 않고 오래된 노트를 재생하며 시스템이 무엇을 지속(durable) 항목으로 판단하는지 점검하고 싶을 때 유용합니다.</p><p>다음을 실행하면,</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rem-backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./memory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage-short-term</span></span></code></pre></div><p>grounded durable 후보는 바로 승격되지 않습니다. 일반 deep phase가 이미 사용하는 동일한 단기 dreaming 저장소에 스테이징됩니다. 즉,</p><ul><li><code>DREAMS.md</code>는 사람이 검토하는 surface로 유지됩니다.</li><li>단기 저장소는 기계가 사용하는 ranking surface로 유지됩니다.</li><li><code>MEMORY.md</code>는 여전히 deep promotion을 통해서만 기록됩니다.</li></ul><p>재생이 유용하지 않았다고 판단되면, 일반 diary 항목이나 일반 recall 상태를 건드리지 않고 스테이징된 아티팩트를 제거할 수 있습니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rem-backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rollback</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rem-backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rollback-short-term</span></span></code></pre></div><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Check index status and provider</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;query&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Search from the command line</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> index</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Rebuild the index</span></span></code></pre></div><h2 id="더-읽어보기" tabindex="-1">더 읽어보기 <a class="header-anchor" href="#더-읽어보기" aria-label="Permalink to &quot;더 읽어보기&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/memory-builtin">Builtin Memory Engine</a> -- 기본 SQLite 백엔드</li><li><a href="/openclaw-docs-ko/concepts/memory-qmd">QMD Memory Engine</a> -- 고급 local-first 사이드카</li><li><a href="/openclaw-docs-ko/concepts/memory-honcho">Honcho Memory</a> -- AI 네이티브 크로스 세션 memory</li><li><a href="/openclaw-docs-ko/plugins/memory-wiki">Memory Wiki</a> -- 컴파일된 지식 저장소와 wiki 네이티브 도구</li><li><a href="/openclaw-docs-ko/concepts/memory-search">Memory Search</a> -- 검색 파이프라인, 제공자, 튜닝</li><li><a href="/openclaw-docs-ko/concepts/dreaming">Dreaming</a> -- 단기 recall에서 장기 memory로의 백그라운드 promotion</li><li><a href="/openclaw-docs-ko/reference/memory-config">Memory 설정 레퍼런스</a> -- 모든 설정 옵션</li><li><a href="/openclaw-docs-ko/concepts/compaction">Compaction</a> -- compaction과 memory의 상호작용</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/active-memory">Active memory</a></li><li><a href="/openclaw-docs-ko/concepts/memory-search">Memory search</a></li><li><a href="/openclaw-docs-ko/concepts/memory-builtin">Builtin memory engine</a></li><li><a href="/openclaw-docs-ko/concepts/memory-honcho">Honcho memory</a></li></ul>`,50)])])}const k=i(l,[["render",r]]);export{h as __pageData,k as default};
